async (page) => {
  await page.evaluate(() => {
    const btn = document.getElementById('quest-button');
    if (btn) btn.click();
  });
  await page.waitForTimeout(1000);
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  return state;
}

async (page) => {
  const result = await page.evaluate((id) => window.__talkToNPC(id), '1-4633474');
  await page.waitForTimeout(1500);
  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    return JSON.stringify({
      pos: s.player_position,
      quests: s.quests,
      ui: s.ui_state,
      dist_blacksmith: s.nearby_entities.find(e => e.name === 'Blacksmith')?.distance
    });
  });
  return state;
}

